@startuml
skinparam classAttributeIconSize 0
skinparam noteBackgroundColor #FFFFCC
skinparam noteBorderColor #CCCCCC
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #666666
  ArrowColor #333333
}
skinparam classHeaderBackgroundColor #E8E8E8

title 策略模式

class Context {
  + algorithm(): void
  + setStrategy(Strategy): void
}

class Strategy {
  + algorithm(): void
}

class ConcreteStrategyA {
  + algorithm(): void
}

class ConcreteStrategyB {
  + algorithm(): void
}

Context "1" *-- "1" Strategy : 组合
Strategy <|-- ConcreteStrategyA : 泛化
Strategy <|-- ConcreteStrategyB : 泛化

note right of Context
  strategy->algorithm();
end note

note right of Strategy
  策略模式和状态模式区别:策略模式一般用于单个算法，而状态模式的每个状态子类中
  需要包含所有原来的语境类（Context）中的所有方法的具体实现。
end note

@enduml
